import Add from "@/views/protal/view/add";
import {getApiUrl} from "@/utils/utils";
import userApi from '@/api/vide/vide'
import Cookies from 'js-cookie'
import emilApi from "@/api/message/message";
import {getToken} from "@/utils/auth";

export default {
  components: {Add},
  data() {
    return {
      flage:null,
      form:{
        email:""
      },
      uploadUrl: '',
      uploadHeaders: {
        'Authorization': ''
      },
    }
  },
  created() {
    this.init()
  },
  methods: {

   //查询当前用户是否是管理员
    init() {
      debugger
      this.getUseres()
      this.uploadUrl = getApiUrl()
      this.uploadHeaders['Authorization'] = getToken()
    },
    mounted: function mounted() {
      debugger
      this.getUseres();
    },
    getUseres() {
      userApi.getUser().then(response => {
        debugger
        this.flage = response.data
      })
    },


    send() {
      //判断是否登录
      debugger
      let  ser =Cookies.get("vue_admin_template_token");
      if (ser == undefined ) {
       //未登录
        this.$message({
          message: 'not log in',
          type: 'success'
        })
        this.$router.push('/login');
      }else{
        //已登录发送视频到邮箱
        emilApi.sendVode(this.form.email,this.uploadUrl).then(response => {
          this.$message({
            message: 'send successfully',
            type: 'success'
          })

        })

      }
    }
  }
}
